var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 왜 여기에 침식체가 있는 거야?","JPN":"どういうことだ？　なぜここに侵食体がいる？","ENG":"What’s going on? Why is this C.O. here?","TWN":"這是怎麼回事？這裡怎麼會有侵蝕體？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"왜 이래. 순진한 척을 다하네.","JPN":"なによ、何も知らないみたいな顔して。","ENG":"Come on, don't pretend you don't know.","TWN":"哎唷～不要再演了啦～"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"보면 알잖아. 저게 동생이 지키던 <color=#ffd34c>강아지</color>야.","JPN":"見ればわかるでしょ。あれが弟クンが守っていた<color=#ffd34c>仔犬</color>よ。","ENG":"It's obvious. It's the <color=#ffd34c>puppy</color> you've been protecting.","TWN":"這不是很明顯嗎？他就是你在保護的<color=#ffd34c>狗狗</color>。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……강아지라고? 저게?","JPN":"……仔犬だと？　あれが？","ENG":"A puppy? That's a puppy?","TWN":"……狗狗？你說他？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그래. 최근 일부 부유층들 사이에서 유행하는 반려 침식체라나 뭐라나.","JPN":"そうよ。最近、一部の富裕層の間で流行っているペット侵食体だとか。","ENG":"Yes. C.O. pets have grown quite popular among the rich nowadays.","TWN":"對啊，最近那些有錢人流行把侵蝕體當作寵物飼養。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"저대로 놔두면 온 집안 사람들이 침식 증후군을 일으키게 되는 것도 시간 문제겠지.","JPN":"そのままにしておけば、一家が侵食症候群を起こすのも時間の問題でしょうね。","ENG":"Leave it alone, and everyone in this household will soon experience Corruption Syndrome.","TWN":"再這樣下去，全家感染侵蝕症候群也只是早晚的問題。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 저 괴물을 없애 달라고 한 건……. 가족 중 한 명이겠군.","JPN":"じゃあ、あの化物を処理してほしいと頼んだのも……ここの家族の一人なのか。","ENG":"So, someone in the household asked you to get rid of it.","TWN":"所以是其中一位家人……請你把那個怪物除掉嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BUMP"},{"id":"L11_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"정답. 아무리 답답한 집구석에도 정신머리 제대로 박힌 사람은 있기 마련이야.","JPN":"正解。流行りに乗るようなミーハーなお金持ちの家にも、一人ぐらいはちゃんとした人がいるものよ。","ENG":"Correct. In every family, there's at least one person who has their wits about them.","TWN":"正確，再怎麼糟糕的家族，裡面還是會有一個腦袋正常的人。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"거액을 주면서 의뢰하길래 덥석 받았지.","JPN":"巨額を提示して依頼してきたから、喜んで受けたの。","ENG":"Also, I couldn't resist the amount of money they offered.","TWN":"人家出這麼高價的委託，當然要馬上接受囉～"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"정확히는 <color=#ffd34c>괴도 르블랑</color>에게 의뢰한 걸, 내가 선수친 거지만.","JPN":"正確には<color=#ffd34c>怪盗ルブラン</color>に依頼したものを、アタシが先取りしたわけだけど。","ENG":"Well, technically speaking, they offered it to <color=#ffd34c>LeBlanc the Thief</color>; but I just cut in.","TWN":"正確來說，人家是委託<color=#ffd34c>怪盜布勒朗</color>啦，只是我先下手為強而已。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래……. 역시 사칭이었군.","JPN":"そうか……やはり詐称だったんだな。","ENG":"I see. So, you're just an imposter.","TWN":"我就知道……原來你是冒牌貨。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BUMP"},{"id":"L15_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"왜, 괴도 르블랑이랑 한 판 붙을 생각에 두근두근했어?","JPN":"なによ、怪盗ルブランと対決できると思ってワクワクしてたの？","ENG":"Why, were you excited to have a match with the legendary thief?","TWN":"怎樣？你很想跟怪盜布勒朗打一架是吧？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"상황 파악 끝났으면 이 밧줄이나 좀 풀어 줘. 나 바쁜 여자야.","JPN":"状況把握が終わったなら、この縄を外してよ。アタシは忙しい女なの。","ENG":"Now that you know what's going on, you should untie me. I'm a busy woman.","TWN":"既然事情的來龍去脈都已經弄清楚了，還不快鬆開我，姊姊很忙的好嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니, 지금 강아지도 아니고 침식체를 훔쳐가겠다고? 제정신이야?","JPN":"つまり、あんたがここに来た理由は犬ではなく、侵食体を盗むためってことか？　正気か？","ENG":"What? Do you still want to steal that thing? Are you crazy?","TWN":"等等，意思是你要偷的不是狗，而是侵蝕體？你是腦袋破洞嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BUMP"},{"id":"L20_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"맞아. 그러니까 여기서 해치워 버리려고.","JPN":"そうよ。盗むのは難しいから、ここで倒してしまおうと思って。","ENG":"I'm not. I want to take care of it right here and now.","TWN":"沒錯啊，所以我打算直接在這裡處理掉。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐? 그건 절대 안 돼!","JPN":"は？　それは絶対にダメだ！","ENG":"What? No, you can't!","TWN":"什麼？不可以！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"불의를 보고도 모른 척하는 사람이었어, 동생?","JPN":"弟クンは、不義を見ても知らない振りをする人だったの？　","ENG":"Can you look away from such injustice, brother?","TWN":"小老弟，你是會對不法的事視而不見的人嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니. 여기서 네 손으로는 절대 못 죽여.","JPN":"いや、ここでは絶対に殺させない。","ENG":"No, but I'm not going to let you kill it right now.","TWN":"不是，但你不能在這裡出手！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내가 무사히 의뢰비를 받고 나서 죽이든 말든 해. 아니면 가져간 보상금을 내놓거나.","JPN":"俺が無事報酬をもらってから、殺すも飼うも好きにしてくれ。それか、盗んで行った報奨金を返すかだ。","ENG":"If you really want to do it, do it after I get paid. Or you can just give back the money you stole from me.","TWN":"看你是要等到我拿到委託費後再出手，還是你要把獎金還來？！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"끼어들어서 미안한데.","JPN":"ねえ、話の途中で悪いんだけど。","ENG":"I'm sorry to interrupt you, but—","TWN":"真不好意思，打個岔…"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"또 은근슬쩍 말 돌릴 생각이라면…….","JPN":"また話をそらすつもりなら……","ENG":"No buts. If you're trying to distract me again—","TWN":"你不要又想打什麼鬼主意……"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"저기 문짝 곧 날아가겠는데?","JPN":"あそこの扉が壊れる寸前よ？","ENG":"It's trying to break the door down.","TWN":"門都快被撞爛咧？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잠깐! 저 놈 아까까지 방 안에 얌전히 있었잖아!","JPN":"おいおい！　さっきまで部屋の中に大人しくしてたはずなのに！","ENG":"But why? It's been quiet all this time!","TWN":"怎麼會這樣！他剛剛不是還乖乖地待在房裡嗎？！"},"stage":{"bg":"HALL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L33_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"동생 얼굴 보니까 깨물어 주고 싶어졌겠지! 이거나 어서 풀어!","JPN":"弟クンの顔を見たらじゃれたくなったみたいね！　早くこれを解いて！","ENG":"I don't know, maybe it suddenly decided to bite your face off. Come on, release me!","TWN":"可能是因為看到你的臉，激起他想要咬你的慾望吧！快把我鬆開啦！"},"stage":{"bg":"HALL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아, 알았어! 알았다고! 젠장!!","JPN":"わ、わかった！　わかったよ！　クソ！！","ENG":"O-okay! Okay! Crap!","TWN":"喔，好好好！知道啦！該死的！！"},"stage":{"bg":"HALL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};